(86, 84, 84, '2025-11-04 08:40:15', '2025-11-04 08:27:22', 'PROD-038', 'Conception & Mise en Service de votre site internet', '<p><strong>Conception &amp; Développement (LiteSpeed/Responsive) :</strong>&nbsp;</p><ul><li>Développement sous <strong>WordPress</strong>, CMS leader mondial, offrant autonomie et évolutivité.</li><li>Création du site vitrine professionnel (max. 10 pages : Accueil, Menu, Galerie, Contact, Infos pratiques, Mentions Légales, etc.),&nbsp;</li><li>Design Responsive optimisé (adapté aux mobiles, tablettes et ordinateurs)</li><li>Optimisation des performances et compatibilité <strong>LiteSpeed</strong> pour des temps de chargement ultra-rapides.</li></ul><p><strong>Contenu Visuel Professionnel :</strong>&nbsp;</p><ul><li><strong>Shooting photo sur site</strong> (½ journée) incluant plats signature, ambiance de la salle, et portraits d\'équipe.&nbsp;</li><li>Rédaction et Intégration des <strong>contenus </strong>: textes, carte/menu dynamique, horaires, contacts, mentions légales.</li></ul><p><strong>Optimisation SEO initiale :</strong></p><ul><li>Recherche de <strong>mots-clés locaux</strong> pertinents (ville, spécialités, type de cuisine)</li><li>Rédaction des <strong>balises titre, méta-description et attributs ALT</strong></li><li>Structuration sémantique (balises Hn, URL propres)</li><li><strong>Maillage interne</strong> et optimisation des images</li><li>Connexion au <strong>Google Business Profile</strong> et à <strong>Google Search Console</strong></li></ul><p><strong>Mise en Service :</strong> Installation sur l\'hébergement, configuration du Nom de Domaine, tests finaux et mise en ligne.&nbsp;</p><p>&nbsp;</p>', 3590.00, NULL, 'service', 70, NULL, 0, NULL, NULL, 1, 0, 1, NULL, 0),
(87, 84, 84, '2025-11-04 09:04:03', '2025-11-04 08:43:32', 'PROD-039', 'Hébergement, Maintenance & SEO Formule Avancée - Paiement mensuel - Engagement annuel', '<p><strong>Hébergement professionnel LiteSpeed</strong> sur serveur haute performance, incluant certificat SSL, sauvegardes automatiques quotidiennes et supervision 24/7.</p><p><strong>Maintenance technique WordPress</strong> : mises à jour du CMS, des extensions et du thème, surveillance de la sécurité, corrections mineures et contrôle de compatibilité.</p><p><strong>Assistance technique prioritaire</strong> : support par e-mail ou téléphone sous 48h ouvrées pour tout incident ou besoin de mise à jour mineure.</p><p><strong>Optimisation SEO continue</strong> : suivi des performances de positionnement local, ajustement des balises, optimisation de la vitesse, mise à jour des contenus clés et maintien du référencement Google Business Profile.</p><p><strong>Sauvegardes </strong>quotidiennes avec rétention 30 jours</p><p>L’abonnement garantit la stabilité, la performance et la visibilité du site sur le long terme.<br>Engagement minimum : 12 mois, renouvelable tacitement. Résiliation possible à l’échéance avec préavis de 30 jours.</p>', 119.00, NULL, 'service', 70, NULL, 1, 1, 2, 1, 0, 1, NULL, 0),
(88, 84, 84, '2025-11-04 09:00:13', '2025-11-04 08:46:16', 'PROD-040', 'Hébergement, Maintenance & SEO Formule Essentielle- Paiement mensuel - Engagement annuel', '<p><strong>Hébergement professionnel LiteSpeed</strong> sur serveur haute performance, incluant certificat SSL, sauvegardes automatiques quotidiennes et supervision 24/7.</p><p><strong>Maintenance technique WordPress</strong> : mises à jour du CMS, des extensions et du thème, surveillance de la sécurité, corrections mineures et contrôle de compatibilité.</p><p><strong>Assistance technique prioritaire</strong> : support par e-mail ou téléphone sous 48h ouvrées pour tout incident ou besoin de mise à jour mineure.</p><p>L’abonnement garantit la stabilité, la performance et la visibilité du site sur le long terme.<br>Engagement minimum : 12 mois, renouvelable tacitement. Résiliation possible à l’échéance avec préavis de 30 jours.</p>', 69.00, NULL, 'service', 70, NULL, 1, NULL, NULL, 1, 0, 1, NULL, 0),
(90, 84, 84, '2025-11-04 09:03:53', '2025-11-04 09:00:33', 'PROD-041', 'Hébergement, Maintenance & SEO Formule Premium- Paiement mensuel - Engagement annuel-copy', '<p><strong>Hébergement professionnel LiteSpeed</strong> sur serveur haute performance, incluant certificat SSL, sauvegardes automatiques quotidiennes et supervision 24/7.</p><p><strong>Maintenance technique WordPress</strong> : mises à jour du CMS, des extensions et du thème, surveillance de la sécurité, corrections mineures et contrôle de compatibilité.</p><p><strong>Assistance technique prioritaire</strong> : support par e-mail ou téléphone sous 24h ouvrées pour tout incident ou besoin de mise à jour mineure.</p><p><strong>Optimisation SEO continue</strong> : suivi des performances de positionnement local, ajustement des balises, optimisation de la vitesse, mise à jour des contenus clés et maintien du référencement Google Business Profile.</p><p><strong>Sauvegardes </strong>quotidiennes avec rétention 30 jours</p><p><strong>SEO éditorial mensuel</strong> : optimisation de 1 à 2 pages ou actualités / articles pour booster le référencement</p><p><strong>Reporting trimestriel</strong> : performance, sécurité, référencement</p><p>L’abonnement garantit la stabilité, la performance et la visibilité du site sur le long terme.<br>Engagement minimum : 12 mois, renouvelable tacitement. Résiliation possible à l’échéance avec préavis de 30 jours.</p>', 179.00, NULL, 'service', 70, NULL, 1, NULL, NULL, 1, 0, 1, NULL, 0),
