(992, '2025-11-04 08:44:17', '2025-11-04 09:04:38', 84, 84, 418, 'Conception & Mise en Service de votre site internet', '<p><strong>Conception &amp; Développement (LiteSpeed/Responsive) :</strong>&nbsp;</p><ul><li>Développement sous <strong>WordPress</strong>, CMS leader mondial, offrant autonomie et évolutivité.</li><li>Création du site vitrine professionnel (max. 10 pages : Accueil, Menu, Galerie, Contact, Infos pratiques, Mentions Légales, etc.),&nbsp;</li><li>Design Responsive optimisé (adapté aux mobiles, tablettes et ordinateurs)</li><li>Optimisation des performances et compatibilité <strong>LiteSpeed</strong> pour des temps de chargement ultra-rapides.</li></ul><p><strong>Contenu Visuel Professionnel :</strong>&nbsp;</p><ul><li><strong>Shooting photo sur site</strong> (½ journée) incluant plats signature, ambiance de la salle, et portraits d\'équipe.&nbsp;</li><li>Rédaction et Intégration des <strong>contenus </strong>: textes, carte/menu dynamique, horaires, contacts, mentions légales.</li></ul><p><strong>Optimisation SEO initiale :</strong></p><ul><li>Recherche de <strong>mots-clés locaux</strong> pertinents (ville, spécialités, type de cuisine)</li><li>Rédaction des <strong>balises titre, méta-description et attributs ALT</strong></li><li>Structuration sémantique (balises Hn, URL propres)</li><li><strong>Maillage interne</strong> et optimisation des images</li><li>Connexion au <strong>Google Business Profile</strong> et à <strong>Google Search Console</strong></li></ul><p><strong>Mise en Service :</strong> Installation sur l\'hébergement, configuration du Nom de Domaine, tests finaux et mise en ligne.&nbsp;</p><p>&nbsp;</p>', 1, NULL, 1, 3590, 20, 2872, 86, 1, 0, NULL, 20, 31, 0),
