REPLACE INTO `ticket_tkt` VALUES (1, 'TKT260001', '2026-04-21 06:27:10', '2026-04-21 06:27:58', 84, 84, 'Un bug dans la matrice', 3, 3, 244, 1, 42, NULL, 1, NULL, NULL, 3849, 3849, '2026-04-21 08:27:10', NULL, NULL, NULL, NULL, NULL, NULL);
REPLACE INTO `ticket_article_tka` VALUES (1, '2026-04-21 06:27:10', '2026-04-21 06:27:10', 84, 84, 1, 3849, 3849, NULL, '<p>Vous nous avez contacté afin de notifier un bug dans la matrice</p>\n<p>Bien à vous </p>', '2026-04-21 08:27:10', 10, 0, NULL, NULL, 0);
REPLACE INTO `ticket_article_tka` VALUES (2, '2026-04-21 06:27:44', '2026-04-21 06:27:44', 84, 84, 1, NULL, 3849, NULL, '<p>Nous avons bien visualiser ce bug et nous vous remercions de l\'avoir remonté.</p>\n<p> </p>', '2026-04-21 08:27:44', 2, 0, NULL, 84, 0);
REPLACE INTO `ticket_article_tka` VALUES (3, '2026-04-21 06:27:58', '2026-04-21 06:27:58', 84, 84, 1, NULL, NULL, NULL, '<p>Contacter Neo !</p>', '2026-04-21 08:27:58', 30, 1, NULL, 84, 0);
REPLACE INTO `ticket_tkt` VALUES (1, 'TKT260001', '2026-04-21 06:27:10', '2026-04-21 06:27:58', 84, 84, 'Défaut d\'alimentation 1.21 Gigowatts', 3, 3, 244, 1, 42, NULL, 1, NULL, NULL, 3849, 3849, '2026-04-21 08:27:10', NULL, NULL, NULL, NULL, NULL, NULL);
REPLACE INTO `ticket_article_tka` VALUES (1, '2026-04-21 06:27:10', '2026-04-21 06:27:10', 84, 84, 1, 3849, 3849, NULL, '<p>Vous nous avez contacté car le convecteur temporel ne reçoit pas assez d\'énergie pour le saut à 88 mph.</p>\n<p>Nom de Zeus !</p>', '2026-04-21 08:27:10', 10, 0, NULL, NULL, 0);
REPLACE INTO `ticket_article_tka` VALUES (2, '2026-04-21 06:27:44', '2026-04-21 06:27:44', 84, 84, 1, NULL, 3849, NULL, '<p>Nous avons vérifié les circuits. Il semblerait que le condensateur de flux soit mal branché sur la batterie.</p>', '2026-04-21 08:27:44', 2, 0, NULL, 84, 0);
REPLACE INTO `ticket_article_tka` VALUES (3, '2026-04-21 06:27:58', '2026-04-21 06:27:58', 84, 84, 1, NULL, NULL, NULL, '<p>Action : Attendre que la foudre tombe sur le clocher à 22h04 précises.</p>', '2026-04-21 08:27:58', 30, 1, NULL, 84, 0);
REPLACE INTO `ticket_tkt` VALUES (2, 'TKT260002', '2026-04-21 09:15:00', '2026-04-21 10:30:00', 84, 84, 'Nettoyage carrosserie suite accident', 2, 1, 245, 1, 42, NULL, 1, NULL, NULL, 3850, 3850, '2026-04-21 11:15:00', NULL, NULL, NULL, NULL, NULL, NULL);
REPLACE INTO `ticket_article_tka` VALUES (4, '2026-04-21 09:15:00', '2026-04-21 09:15:00', 84, 84, 2, 3850, 3850, NULL, '<p>Client (B. Tannen) furieux. La voiture est recouverte de fumier suite à une course-poursuite en skate.</p>', '2026-04-21 11:15:00', 10, 0, NULL, NULL, 0);
REPLACE INTO `ticket_article_tka` VALUES (5, '2026-04-21 10:30:00', '2026-04-21 10:30:00', 84, 84, 2, NULL, NULL, NULL, '<p>Action : Facturer 300$ de frais de nettoyage. Ne pas prêter attention aux menaces du client.</p>', '2026-04-21 12:30:00', 30, 1, NULL, 84, 0);
REPLACE INTO `ticket_tkt` VALUES (3, 'TKT260003', '2026-04-21 14:00:00', '2026-04-21 15:45:00', 84, 84, 'Effacement progressif des données photos', 1, 4, 246, 1, 42, NULL, 1, NULL, NULL, 3851, 3851, '2026-04-21 16:00:00', NULL, NULL, NULL, NULL, NULL, NULL);
REPLACE INTO `ticket_article_tka` VALUES (6, '2026-04-21 14:00:00', '2026-04-21 14:00:00', 84, 84, 3, 3851, 3851, NULL, '<p>Alerte : Le frère et la sœur du client disparaissent de la photo de famille.</p>', '2026-04-21 16:00:00', 10, 0, NULL, NULL, 0);
REPLACE INTO `ticket_article_tka` VALUES (7, '2026-04-21 15:45:00', '2026-04-21 15:45:00', 84, 84, 3, NULL, NULL, NULL, '<p>Action urgente : Faire en sorte que George et Lorraine dansent ensemble au bal de l\'Enchantement sous la Mer.</p>', '2026-04-21 17:45:00', 30, 1, NULL, 84, 0);
REPLACE INTO `ticket_tkt` VALUES (4, 'TKT260004', '2026-04-21 16:20:00', '2026-04-21 17:10:00', 84, 84, 'Panne de propulsion sur plan d\'eau', 3, 2, 247, 1, 42, NULL, 1, NULL, NULL, 3852, 3852, '2026-04-21 18:20:00', NULL, NULL, NULL, NULL, NULL, NULL);
REPLACE INTO `ticket_article_tka` VALUES (8, '2026-04-21 16:20:00', '2026-04-21 16:20:00', 84, 84, 4, 3852, 3852, NULL, '<p>L\'hoverboard rose s\'est arrêté au-dessus du bassin de l\'Hôtel de Ville.</p>', '2026-04-21 18:20:00', 10, 0, NULL, NULL, 0);
REPLACE INTO `ticket_article_tka` VALUES (9, '2026-04-21 17:10:00', '2026-04-21 17:10:00', 84, 84, 4, NULL, NULL, NULL, '<p>Rappel technique : Les hoverboards ne fonctionnent pas sur l\'eau, sauf si vous avez de la puissance !</p>', '2026-04-21 19:10:00', 30, 1, NULL, 84, 0);
REPLACE INTO `ticket_tkt` VALUES (5, 'TKT260005', '2026-04-21 18:00:00', '2026-04-21 19:00:00', 84, 84, 'Date système bloquée en 1885', 3, 3, 248, 1, 42, NULL, 1, NULL, NULL, 3853, 3853, '2026-04-21 20:00:00', NULL, NULL, NULL, NULL, NULL, NULL);
REPLACE INTO `ticket_article_tka` VALUES (10, '2026-04-21 18:00:00', '2026-04-21 18:00:00', 84, 84, 5, 3853, 3853, NULL, '<p>Le clavier temporel est bloqué sur le 12 novembre 1885. Impossible de revenir en 1985.</p>', '2026-04-21 20:00:00', 10, 0, NULL, NULL, 0);
REPLACE INTO `ticket_article_tka` VALUES (11, '2026-04-21 19:00:00', '2026-04-21 19:00:00', 84, 84, 5, NULL, NULL, NULL, '<p>Action : Chercher une locomotive à vapeur pour atteindre les 88 miles à l\'heure.</p>', '2026-04-21 21:00:00', 30, 1, NULL, 84, 0);
